/// <summary>
/// Extension of the <c>PrintMgmtDelegatesHandler</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(PrintMgmtDelegatesHandler))]
public final class PrintMgmtDelegatesHandlerETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Gets the default report format for specified document types in the ETGSPAIN model.
/// </summary>
/// <param name="_docType">The document type for which to get the default report format.</param>
/// <returns>
/// Returns the default <c>PrintMgmtReportFormatName</c> for the specified document type.
/// </returns>
protected static PrintMgmtReportFormatName getDefaultReportFormat(PrintMgmtDocumentType _docType)
{
    PrintMgmtReportFormatName	ret = next getDefaultReportFormat(_docType);

    switch (_docType)
    {
        case PrintMgmtDocumentType::SalesAgreementConfirmation:
        case PrintMgmtDocumentType::PurchAgreementConfirmation:
            return ssrsReportStr(ETGSPAINAgreementConfirmation, Report);
        case PrintMgmtDocumentType::SalesOrderConfirmation:
            return ssrsReportStr(ETGSPAINSalesConfirm, Report);  
            /*
        case PrintMgmtDocumentType::SalesOrderInvoice:
            return ssrsReportStr(ETGSPAINSalesInvoice, Report);
            */
    }

    return ret;
}
